insert into public.disease_localizations
  (disease_id, language_tag, name, description, symptom_preview, causes, prevention, guidance, when_to_act, disclaimer)
values
  ('leaf-spot','en','Leaf Spot','Spots can affect eggplant leaves and may progress to stems or fruit.','Brown or black spots that may yellow, dry, or tear.','Often associated with fungal or bacterial pathogens and prolonged leaf wetness.','Improve airflow, space plants, water near soil, and clean tools.','Isolate badly affected material and ask an agricultural specialist to confirm the cause before choosing a control.','Act when spots spread quickly, leaves drop, or stems and fruit develop lesions.','Screening aid only; similar symptoms can have different causes. Consult a qualified agricultural specialist before treatment.'),
  ('leaf-spot','fil','Leaf Spot','Maaaring maapektuhan ang dahon at kumalat sa tangkay o bunga.','Kayumanggi o itim na batik na maaaring manilaw, matuyo, o mapunit.','Madalas kaugnay ng fungal o bacterial pathogens at matagal na pagkabasa ng dahon.','Pagandahin ang airflow, pagitan ng tanim, pagdidilig sa lupa, at kalinisan ng kagamitan.','Ihiwalay ang malubhang apektadong bahagi at ipakumpirma ang sanhi sa agricultural specialist.','Kumilos kapag mabilis dumami ang batik, nalalagas ang dahon, o may sugat sa tangkay at bunga.','Pantulong lamang sa paunang pagsusuri; maaaring magkapareho ang sintomas ng magkaibang sanhi. Kumonsulta muna sa espesyalista.'),
  ('mosaic-virus','en','Mosaic Virus','Virus-like symptoms can distort leaves and reduce growth.','Yellow-green mosaic patterns with curled or distorted growth.','Plant viruses may spread through infected seed, plant material, tools, or insect vectors.','Use clean seed and tools, manage vectors, and avoid propagating suspicious plants.','Isolate suspicious plants and sanitize hands and tools; no treatment removes a virus from an infected plant.','Act promptly when mosaic patterns and distorted new growth appear across plants.','Screening aid only; laboratory or specialist confirmation is needed for a virus diagnosis.'),
  ('mosaic-virus','fil','Mosaic Virus','Maaaring baluktutin ng virus-like symptoms ang dahon at pahinain ang paglaki.','Dilaw-berdeng mosaic pattern at kulot o baluktot na tubo.','Maaaring kumalat ang plant virus sa kontaminadong binhi, halaman, kagamitan, o insect vector.','Gumamit ng malinis na binhi at kagamitan, bantayan ang vector, at huwag paramihin ang kahina-hinalang halaman.','Ihiwalay ang halaman at linisin ang kamay at kagamitan; walang lunas na nag-aalis ng virus sa apektadong halaman.','Kumilos agad kapag may mosaic pattern at baluktot na bagong tubo sa maraming halaman.','Pantulong lamang sa screening; kailangan ang laboratoryo o espesyalista para makumpirma ang virus.'),
  ('white-molds','en','White Molds','Cottony growth may occur on stems, leaves, or fruit.','White cotton-like growth, soft tissue, wilting, or black sclerotia.','Commonly associated with Sclerotinia favored by cool, humid, wet, or crowded conditions.','Reduce moisture, improve airflow, and avoid casually composting infected material.','Remove and isolate affected plants without spreading black sclerotia.','Act immediately when cottony growth, soft rot, sudden wilt, or sclerotia appear.','Screening aid only; confirm the organism before applying a fungicide or other treatment.'),
  ('white-molds','fil','Puting Amag','Maaaring lumitaw ang tila bulak na amag sa tangkay, dahon, o bunga.','Puting tila bulak, malambot na tisyu, pagkalanta, o itim na sclerotia.','Karaniwang kaugnay ng Sclerotinia na lumalala sa malamig, mahalumigmig, basa, o siksik na tanim.','Bawasan ang moisture, pagandahin ang airflow, at huwag basta i-compost ang apektadong materyal.','Alisin at ibukod ang apektadong halaman nang hindi ikinakalat ang itim na sclerotia.','Kumilos agad kapag may tila bulak, soft rot, biglang wilt, o sclerotia.','Pantulong lamang sa screening; ipakumpirma ang organism bago gumamit ng fungicide o ibang treatment.'),
  ('wilt','en','Wilt','Leaves droop, yellow, and may remain dry on weakened plants.','Persistent drooping, yellow lower leaves, and weak stems.','Possible causes include Verticillium, root rot, root injury, or water stress.','Avoid waterlogging and moving soil from affected beds; use clean growing material.','Check soil moisture and roots, isolate affected plants, and seek specialist confirmation.','Act when correct watering does not restore the plant or wilting spreads.','Screening aid only; several root, vascular, and water problems look alike.'),
  ('wilt','fil','Pagkalanta','Yumuyuko at naninilaw ang dahon at maaaring manatiling tuyo sa mahinang halaman.','Patuloy na pagyuko, dilaw na ibabang dahon, at mahinang tangkay.','Maaaring Verticillium, root rot, pinsala sa ugat, o problema sa tubig.','Iwasan ang waterlogging at paglipat ng lupa mula sa apektadong tanim; gumamit ng malinis na materyal.','Suriin ang moisture at ugat, ihiwalay ang halaman, at ipakumpirma sa espesyalista.','Kumilos kapag hindi bumabalik ang sigla matapos ang tamang pagdidilig o kumakalat ang pagkalanta.','Pantulong lamang sa screening; magkakahawig ang ilang problema sa ugat, vascular tissue, at tubig.'),
  ('insect-pest','en','Insect Pest','Chewing or sap-feeding insects can damage eggplant leaves, shoots, stems, or fruit.','Irregular holes, chewed edges, insects, eggs, or feeding scars.','Different insects and life stages cause similar visible damage.','Inspect plants often, keep the area clean, and protect beneficial insects.','Inspect both leaf surfaces, shoots, stems, and fruit and photograph the pest for identification.','Act when damage spreads quickly, new growth or fruit is affected, or plants wilt.','Screening aid only; identify the exact pest before choosing a pesticide.'),
  ('insect-pest','fil','Pesteng Insekto','Maaaring sirain ng ngumunguya o sumisipsip na insekto ang dahon, usbong, tangkay, o bunga.','Hindi pantay na butas, nguyang gilid, insekto, itlog, o feeding scars.','Magkakahawig ang pinsala ng iba’t ibang insekto at yugto nito.','Regular na inspeksyunin, panatilihing malinis ang paligid, at protektahan ang beneficial insects.','Suriin ang magkabilang panig ng dahon, usbong, tangkay, at bunga at kunan ng malinaw na larawan ang peste.','Kumilos kapag mabilis dumami ang pinsala, apektado ang bagong tubo o bunga, o nalalanta ang halaman.','Pantulong lamang sa screening; tukuyin muna ang eksaktong peste bago pumili ng pestisidyo.'),
  ('melon-thrips','en','Melon Thrips','Tiny thrips can scar and deform eggplant leaves and fruit.','Silvery or bronze areas, curled growth, and tiny insects underneath leaves.','Thrips palmi feeds on foliage and blossoms and may transmit some plant viruses.','Monitor young growth, manage weeds, and conserve beneficial insects.','Use magnification to inspect leaf undersides and shoots; seek advice before insecticide use.','Act when thrips are numerous or bronzing, scarring, and deformation worsen quickly.','Screening aid only; microscopic or specialist confirmation may be needed.'),
  ('melon-thrips','fil','Melon Thrips','Maaaring peklatin at baluktutin ng maliliit na thrips ang dahon at bunga.','Pilak o bronze na bahagi, kulot na tubo, at maliit na insekto sa ilalim ng dahon.','Sumisipsip ang Thrips palmi sa dahon at bulaklak at maaaring magdala ng ilang plant virus.','Bantayan ang batang tubo, kontrolin ang damo, at protektahan ang beneficial insects.','Gumamit ng magnification sa ilalim ng dahon at usbong; kumonsulta bago gumamit ng insecticide.','Kumilos kapag marami ang thrips o mabilis lumalala ang bronzing, scarring, at deformity.','Pantulong lamang sa screening; maaaring kailangan ang microscope o specialist confirmation.'),
  ('fruit-rot','en','Fruit Rot','Soft, dark, or sunken decay can expand across eggplant fruit.','Soft dark patches, sunken tissue, water-soaked lesions, or mold.','Fungal or oomycete diseases can worsen after injury, wetness, contamination, or poor airflow.','Keep fruit off wet soil, handle gently, keep tools clean, and improve airflow.','Separate affected fruit and keep it away from harvest and casual compost.','Act immediately when lesions expand quickly, mold or odor develops, or several fruit are affected.','Screening aid only; confirm the cause before applying a crop treatment.'),
  ('fruit-rot','fil','Pagkabulok ng Bunga','Maaaring kumalat sa bunga ang malambot, maitim, o lumulubog na pagkabulok.','Malambot na maitim na bahagi, lubog na tisyu, basang sugat, o amag.','Maaaring lumala ang fungal o oomycete disease dahil sa sugat, basa, kontaminasyon, o mahinang airflow.','Ilayo ang bunga sa basang lupa, hawakan nang maingat, linisin ang kagamitan, at pagandahin ang airflow.','Ihiwalay ang apektadong bunga at ilayo sa ani at karaniwang compost.','Kumilos agad kapag mabilis lumalaki ang sugat, may amag o amoy, o maraming bunga ang apektado.','Pantulong lamang sa screening; ipakumpirma ang sanhi bago gumamit ng treatment.'),
  ('fruit-borer','en','Fruit Borer','Larvae tunnel into eggplant shoots or fruit and feed inside.','Entry holes, frass around openings, wilted shoots, and internal feeding damage.','Eggplant fruit and shoot borer larvae remain hidden after tunneling into plant tissue.','Inspect frequently, maintain sanitation, and use integrated pest management.','Remove and safely dispose of tunneled shoots and fruit; seek locally appropriate IPM advice.','Act when fresh holes, frass, wilted shoots, or repeated fruit damage appear.','Screening aid only; verify the insect and follow local pesticide regulations and labels.'),
  ('fruit-borer','fil','Fruit Borer','Bumubutas ang larva sa usbong o bunga at kumakain sa loob.','Butas na pasukan, dumi sa paligid, nalantang usbong, at pinsala sa loob.','Nagtatago ang eggplant fruit and shoot borer larva matapos bumutas sa tissue.','Madalas na inspeksyunin, panatilihin ang sanitation, at gumamit ng integrated pest management.','Alisin at ligtas na itapon ang binutas na usbong at bunga; humingi ng angkop na lokal na IPM advice.','Kumilos kapag may sariwang butas, frass, nalantang usbong, o paulit-ulit na sira sa bunga.','Pantulong lamang sa screening; tukuyin ang insekto at sundin ang lokal na regulasyon at pesticide label.')
