on conflict (disease_id, language_tag) do update set
  name=excluded.name, description=excluded.description, symptom_preview=excluded.symptom_preview,
  causes=excluded.causes, prevention=excluded.prevention, guidance=excluded.guidance,
  when_to_act=excluded.when_to_act, disclaimer=excluded.disclaimer, updated_at=now();

on conflict (disease_id, language_tag, position) do update set text=excluded.text;

on conflict (disease_id, language_tag, position) do update set publisher=excluded.publisher,title=excluded.title,url=excluded.url;
